import{c as t,cG as o,cb as d,c8 as e,cf as a,cT as r,ce as n}from"./chunks/framework.BlkIsu1j.js";const i=JSON.parse('{"title":"第 1 章：AI 编程时代的到来","description":"","frontmatter":{"title":"第 1 章：AI 编程时代的到来","outline":"deep","layout":"doc","prev":"/ai/claudecodenew/","next":"/ai/claudecodenew/02-agent-and-model","date":"2026-05-30T10:00:00.000Z"},"headers":[],"relativePath":"ai/claudecodenew/01-ai-coding-era.md","filePath":"ai/claudecodenew/01-ai-coding-era.md","lastUpdated":1780121796000}'),s={id:"frontmatter-title",tabindex:"-1"};const l=t({name:"ai/claudecodenew/01-ai-coding-era.md"},[["render",function(t,i,l,g,p,h){return o(),d("div",null,[e("h1",s,[a(r(t.$frontmatter.title)+" ",1),i[0]||(i[0]=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),i[1]||(i[1]=n('<h2 id="_1-1-传统编程-vs-ai-辅助编程-vs-agentic-coding" tabindex="-1">1.1 传统编程 vs AI 辅助编程 vs Agentic Coding <a class="header-anchor" href="#_1-1-传统编程-vs-ai-辅助编程-vs-agentic-coding" aria-label="Permalink to “1.1 传统编程 vs AI 辅助编程 vs Agentic Coding”">​</a></h2><p>软件开发的方式正在经历一场深刻的范式转移。为了理解 Claude Code 在这个新时代中的位置，我们首先需要厘清三种编程范式之间的本质区别。</p><h3 id="传统编程" tabindex="-1">传统编程 <a class="header-anchor" href="#传统编程" aria-label="Permalink to “传统编程”">​</a></h3><p>在 AI 工具出现之前，一个开发者的典型工作流是这样的：</p><p>打开编辑器，根据需求文档从头编写每一行代码；遇到不熟悉的 API 时，打开浏览器搜索文档，在多个页面之间来回跳转；代码跑不通时，阅读错误日志，在 Stack Overflow 上翻找答案；提交代码前，手动输入 <code>git add</code> 和 <code>git commit -m</code>。</p><p>这个过程中，<strong>开发者是唯一的执行主体</strong>。键盘上的每一个字符、终端里的每一条命令，都来自开发者的直接输入。工具（IDE、文档、搜索引擎）只是被动的信息提供者，它们不会主动理解你的意图，更不会替你执行任何操作。</p><p>传统编程的核心特征是：<strong>人在循环中完成 100% 的决策与执行</strong>。</p><h3 id="ai-辅助编程-copilot-时代" tabindex="-1">AI 辅助编程（Copilot 时代） <a class="header-anchor" href="#ai-辅助编程-copilot-时代" aria-label="Permalink to “AI 辅助编程（Copilot 时代）”">​</a></h3><p>2021 年 GitHub Copilot 的发布标志着一个新时代的开始。AI 不再是问答网站上的静态答案，而是直接嵌入编辑器、实时预测你下一段代码的编程伙伴。</p><p>在 AI 辅助编程模式下，工作流变成了这样：</p><p>你在编辑器中敲代码，AI 以灰色的 &quot;Ghost Text&quot; 形式给出内联建议；你写下一个注释描述意图，AI 生成对应的函数实现；你选中一段重复代码，AI 帮你提取成函数。</p><p>但关键的控制权仍然在你手上：AI <strong>只负责建议</strong>，接受还是拒绝完全由你决定。AI 不会主动去读项目里的其他文件，不会帮你运行测试，更不会替你执行 <code>git commit</code>。它就像坐在你身边的副驾驶——可以帮你观察路况、给你建议，但方向盘的掌控权始终在你。</p><p>AI 辅助编程的核心特征是：<strong>人做决策，AI 做建议</strong>。</p><h3 id="agentic-coding-claude-code-时代" tabindex="-1">Agentic Coding（Claude Code 时代） <a class="header-anchor" href="#agentic-coding-claude-code-时代" aria-label="Permalink to “Agentic Coding（Claude Code 时代）”">​</a></h3><p>2024 年底，Claude Code 的发布再次改变了游戏规则。这一次，AI 从一个&quot;提建议的副驾驶&quot;升级为&quot;能自主执行任务的同事&quot;。</p><p>Agentic Coding 的工作流是这样的：</p><p>你对 AI 说：&quot;在这个项目中添加用户认证功能&quot;——AI 不会只给你一段代码让你自己粘贴。它会先读取项目结构，理解技术栈和现有代码风格；然后设计实现方案，创建新文件、修改现有代码；接着运行安装依赖的命令，执行测试；发现测试失败后，它会自己阅读错误信息，定位问题，修复代码，然后再次运行测试；一切通过后，它生成 commit message 并提交。</p><p>在这个过程中，你的角色从 <strong>&quot;写代码的人&quot;</strong> 变成了 <strong>&quot;定方向 + 审结果的人&quot;</strong>。你不需要告诉 AI 每一步怎么做，只需要描述目标，AI 自主规划并执行。你的核心工作变成了：定义清晰的目标、审查 AI 的产出、在关键决策点做出选择。</p><p>Agentic Coding 的核心特征是：<strong>人定目标，AI 做规划与执行，人审查结果</strong>。</p><h3 id="三种范式的对比" tabindex="-1">三种范式的对比 <a class="header-anchor" href="#三种范式的对比" aria-label="Permalink to “三种范式的对比”">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>传统编程</th><th>AI 辅助编程</th><th>Agentic Coding</th></tr></thead><tbody><tr><td><strong>代码编写</strong></td><td>人写全部</td><td>人写主体，AI 补全片段</td><td>AI 写主体，人修改确认</td></tr><tr><td><strong>文档查阅</strong></td><td>人查文档</td><td>人查文档，AI 偶尔引用</td><td>AI 主动查阅并消化</td></tr><tr><td><strong>调试排错</strong></td><td>人分析日志，人修复</td><td>人分析，AI 辅助修复</td><td>AI 分析日志，AI 修复，人验证</td></tr><tr><td><strong>命令执行</strong></td><td>人手动运行</td><td>人手动运行</td><td>AI 自主运行</td></tr><tr><td><strong>Git 管理</strong></td><td>人手动操作</td><td>人手动操作</td><td>AI 自动生成 message 并提交</td></tr><tr><td><strong>迭代速度</strong></td><td>小时级</td><td>分钟级</td><td>秒级到分钟级</td></tr><tr><td><strong>开发者角色</strong></td><td>执行者</td><td>驾驶员+决策者</td><td>导演+审查者</td></tr><tr><td><strong>代表工具</strong></td><td>IDE、搜索引擎</td><td>GitHub Copilot、Tabnine</td><td>Claude Code</td></tr></tbody></table><p>理解这三种范式的递进关系，是理解本书后续所有内容的基础。Claude Code 不是 Copilot 的&quot;升级版&quot;——它们在本质上是两类不同的工具，解决的是不同层次的问题。</p><hr><h2 id="_1-2-什么是-ai-agent" tabindex="-1">1.2 什么是 AI Agent <a class="header-anchor" href="#_1-2-什么是-ai-agent" aria-label="Permalink to “1.2 什么是 AI Agent”">​</a></h2><p>上一节我们提到了 &quot;Agentic Coding&quot; 这个概念。那么，什么是 Agent？为什么把 Claude Code 称为 AI Agent，而不是 chatbot？</p><h3 id="agent-的核心定义" tabindex="-1">Agent 的核心定义 <a class="header-anchor" href="#agent-的核心定义" aria-label="Permalink to “Agent 的核心定义”">​</a></h3><p>在人工智能领域，<strong>Agent（智能体）</strong> 指的是一个能够<strong>感知环境、自主决策、执行行动</strong>的系统。它不是被动地等待指令然后给出回答，而是主动地与环境交互，根据环境反馈调整自己的行为。</p><p>把这个定义映射到编程工具的语境下，一个 AI Coding Agent 需要具备以下核心能力：</p><table tabindex="0"><thead><tr><th>能力</th><th>说明</th><th>Claude Code 中的体现</th></tr></thead><tbody><tr><td><strong>感知（Perception）</strong></td><td>读取和理解代码库的结构与内容</td><td>读取项目文件、分析目录结构、理解代码逻辑</td></tr><tr><td><strong>推理（Reasoning）</strong></td><td>理解需求，分析问题，制定方案</td><td>将模糊需求转化为具体实现计划</td></tr><tr><td><strong>决策（Decision-making）</strong></td><td>在多个可行方案中选择最优解</td><td>选择合适的工具、设计模式、实现路径</td></tr><tr><td><strong>执行（Execution）</strong></td><td>实际修改代码、运行命令、操作文件</td><td>编辑文件、执行终端命令、管理 Git</td></tr><tr><td><strong>学习（Learning）</strong></td><td>从执行结果中获取反馈并调整策略</td><td>读取命令输出，根据错误信息修正方案</td></tr></tbody></table><p>这五个能力构成了一个完整的 <strong>Agent Loop（智能体循环）</strong>：感知环境 → 分析推理 → 制定决策 → 执行行动 → 观察结果 → 调整策略 → 再次感知……如此往复，直到达成目标。</p><h3 id="从对话机器人到-agent-的进化" tabindex="-1">从对话机器人到 Agent 的进化 <a class="header-anchor" href="#从对话机器人到-agent-的进化" aria-label="Permalink to “从对话机器人到 Agent 的进化”">​</a></h3><p>为了更直观地理解 Agent 的特殊性，我们来看一个具体的对比。假设任务是 <strong>&quot;在这个项目中找出所有未使用的依赖并移除&quot;</strong>。</p><p><strong>ChatGPT（纯对话机器人）</strong>： 你把问题丢给它，它返回一段分析思路，可能附带一段脚本。然后你需要自己把脚本复制到项目中运行，手动检查输出，再自己修改 <code>package.json</code>。ChatGPT 不知道你的项目长什么样，也不会知道你运行脚本后发生了什么。</p><p><strong>GitHub Copilot（代码补全）</strong>： 你打开 <code>package.json</code>，它没有任何反应——这不是补全工具能处理的场景。你需要在终端手动运行 <code>depcheck</code>，然后把输出粘贴到编辑器里，Copilot 可能会帮你补全删除依赖的操作。</p><p><strong>Claude Code（AI Agent）</strong>： 你说&quot;找出未使用的依赖并移除&quot;。Claude Code 自动运行 <code>npx depcheck</code>，读取输出，分析 <code>package.json</code> 和代码中的 <code>import</code> 语句交叉验证，然后精确编辑 <code>package.json</code> 删除未使用的包，最后运行 <code>pnpm install</code> 更新 <code>lock</code> 文件。整个过程你只需要在最后确认结果。</p><p>区别在哪里？ChatGPT 和 Copilot 是<strong>无状态的</strong>——每次交互之间没有连接。而 Claude Code 是一个<strong>持续运行的 Agent</strong>，它记得自己做了什么，看到了什么结果，下一步应该怎么调整。</p><h3 id="agent-的关键特征" tabindex="-1">Agent 的关键特征 <a class="header-anchor" href="#agent-的关键特征" aria-label="Permalink to “Agent 的关键特征”">​</a></h3><p>总结起来，一个真正的 AI Coding Agent 具备以下关键特征，这些也是它区别于普通 AI 编程工具的本质属性：</p><ol><li><p><strong>工具使用能力</strong>：Agent 不是只能&quot;说&quot;，它还能&quot;做&quot;。它操作的是真实的文件系统、终端环境、Git 仓库，不是模拟的沙盒。</p></li><li><p><strong>反馈循环</strong>：Agent 执行操作后会观察结果，如果结果不符合预期，它能自动调整方案重新尝试。这是 Agent 与一次性代码生成工具最本质的区别。</p></li><li><p><strong>上下文持续性</strong>：Agent 在一个会话中保持对项目状态的持续认知。它知道刚才创建了哪个文件、修改了哪段代码，不需要你每次都重新解释背景。</p></li><li><p><strong>自主规划</strong>：Agent 能理解高层级的目标描述，自己拆解成可执行的步骤序列。你说&quot;添加认证功能&quot;，它会规划出：创建用户模型 → 实现注册/登录接口 → 添加中间件 → 写测试 → 更新文档。</p></li><li><p><strong>权限边界</strong>：Agent 在受控的环境中运行，什么操作可以自动执行、什么操作需要你确认，是由你配置的——你在授权，它在执行。</p></li></ol><p>理解 Agent 的这些特征后，你就会明白：Claude Code 不是在 Copilot 的基础上&quot;多加了几个功能&quot;，它是从架构层面做了根本性的重新设计——从一个&quot;建议者&quot;变成了一个&quot;执行者&quot;。</p><hr><h2 id="_1-3-主流-ai-编程工具全景图" tabindex="-1">1.3 主流 AI 编程工具全景图 <a class="header-anchor" href="#_1-3-主流-ai-编程工具全景图" aria-label="Permalink to “1.3 主流 AI 编程工具全景图”">​</a></h2><p>2025 年的 AI 编程工具市场已经形成了几大阵营。理解每个工具的定位和边界，有助于你做出最适合自己的选择。下面这张表从类型、交互方式和定价三个维度给出全景对比：</p><table tabindex="0"><thead><tr><th>工具</th><th>类型</th><th>交互方式</th><th>核心能力</th><th>定价模式</th></tr></thead><tbody><tr><td><strong>GitHub Copilot</strong></td><td>代码补全</td><td>IDE 内联建议</td><td>行级/块级智能补全、Chat 面板</td><td>免费 / $10-39/月</td></tr><tr><td><strong>Cursor</strong></td><td>AI IDE</td><td>IDE + 对话面板</td><td>多文件编辑、Composer、规则系统</td><td>$20/月起</td></tr><tr><td><strong>Windsurf</strong></td><td>AI IDE</td><td>IDE + 流式对话</td><td>Cascade 流式协作、多文件感知</td><td>$15/月起</td></tr><tr><td><strong>Claude Code</strong></td><td>CLI/IDE Agent</td><td>自然语言对话</td><td>完整 Agent Loop、终端控制</td><td>API 按量付费</td></tr><tr><td><strong>Aider</strong></td><td>CLI Agent</td><td>命令行对话</td><td>多文件编辑、Git 集成</td><td>自带 API Key</td></tr><tr><td><strong>Cline</strong></td><td>IDE 插件</td><td>VSCode 内对话</td><td>多模型支持、文件编辑</td><td>自带 API Key</td></tr></tbody></table><h3 id="github-copilot-代码补全的开拓者" tabindex="-1">GitHub Copilot：代码补全的开拓者 <a class="header-anchor" href="#github-copilot-代码补全的开拓者" aria-label="Permalink to “GitHub Copilot：代码补全的开拓者”">​</a></h3><p>Copilot 是这个领域的先驱。它的核心价值在于 <strong>&quot;减少打字量&quot;</strong>——在你编写代码时，它像一个有经验的搭档，能猜到你接下来要写什么。对于重复性高、模式化的代码（如 CRUD 操作、样板代码、测试用例），Copilot 的补全效率极高。</p><p>但 Copilot 的边界也很清晰：它不会主动操作文件系统，不会运行命令，不会管理 Git。它是一个被动的建议者，不是主动的执行者。</p><h3 id="cursor-ai-ide-的标杆" tabindex="-1">Cursor：AI IDE 的标杆 <a class="header-anchor" href="#cursor-ai-ide-的标杆" aria-label="Permalink to “Cursor：AI IDE 的标杆”">​</a></h3><p>Cursor 选择了另一条路：不满足于在现有 IDE 中做插件，而是直接打造一个 AI 原生的 IDE。它的 Composer 功能可以跨越多个文件同时编辑，它的规则系统让你能定义项目级的 AI 行为准则。</p><p>Cursor 的优势在于 <strong>&quot;一体化体验&quot;</strong>——你不需要在 IDE 和 AI 工具之间切换。但代价是：你需要离开你熟悉的 VSCode（Cursor 基于 VSCode 分支，但不完全同步），你的所有配置和习惯需要迁移。</p><h3 id="windsurf-流式协作的新思路" tabindex="-1">Windsurf：流式协作的新思路 <a class="header-anchor" href="#windsurf-流式协作的新思路" aria-label="Permalink to “Windsurf：流式协作的新思路”">​</a></h3><p>Windsurf 提出了 Cascade 流式协作概念，强调 <strong>AI 与开发者同步工作</strong>，而不是回合制对话。它试图让 AI 的介入更自然，更像一个实时协作的配对程序员（Pair Programmer）。</p><h3 id="claude-code-agentic-coding-的领跑者" tabindex="-1">Claude Code：Agentic Coding 的领跑者 <a class="header-anchor" href="#claude-code-agentic-coding-的领跑者" aria-label="Permalink to “Claude Code：Agentic Coding 的领跑者”">​</a></h3><p>Claude Code 的定位与前三者有本质区别。它不是补全工具，不是 AI IDE，而是一个<strong>可以与你的现有 IDE 无缝配合的 AI Agent</strong>。你在 VSCode（或你喜欢的任何编辑器）中工作，Claude Code 作为侧边栏或终端中的一个面板运行，随时等待你的指令。</p><p>Claude Code 的核心差异在于 <strong>&quot;自主执行&quot;</strong>——它可以读文件、写文件、运行命令、操作 Git、搜索网络，并在看到执行结果后自动调整策略。这种完整的 Agent Loop 能力是前三个工具所不具备的。</p><h3 id="如何选择" tabindex="-1">如何选择 <a class="header-anchor" href="#如何选择" aria-label="Permalink to “如何选择”">​</a></h3><ul><li>如果你只需要<strong>写得更快</strong>，Copilot 已经够用。</li><li>如果你希望 <strong>AI 嵌入整个开发体验</strong>，Cursor 或 Windsurf 是不错的选择。</li><li>如果你想让 AI <strong>像一个真正的同事那样干活</strong>——理解项目、自主执行、迭代解决问题——Claude Code 是目前最成熟的选择。</li></ul><p>而且这些工具之间并不互斥。很多开发者日常工作同时使用 Copilot（快速补全）和 Claude Code（复杂任务），发挥各自的优势。</p><hr><h2 id="_1-4-claude-code-的独特定位" tabindex="-1">1.4 Claude Code 的独特定位 <a class="header-anchor" href="#_1-4-claude-code-的独特定位" aria-label="Permalink to “1.4 Claude Code 的独特定位”">​</a></h2><p>在了解了主流工具之后，我们把镜头聚焦到本书的主角——Claude Code。它的独特之处在哪里？为什么说它代表了一种新的编程范式？</p><h3 id="不是-更好的-copilot-而是不同的物种" tabindex="-1">不是&quot;更好的 Copilot&quot;，而是不同的物种 <a class="header-anchor" href="#不是-更好的-copilot-而是不同的物种" aria-label="Permalink to “不是&quot;更好的 Copilot&quot;，而是不同的物种”">​</a></h3><p>一个常见的误解是把 Claude Code 看作 Copilot 的升级版。实际上，它们在设计哲学上就分道扬镳了：</p><ul><li><strong>Copilot 的目标</strong>：让你写代码更快。它优化的是&quot;人类编写代码&quot;这个过程的效率。</li><li><strong>Claude Code 的目标</strong>：让你不用写每行代码。它优化的是&quot;任务从需求到交付&quot;整个流程的效率。</li></ul><p>用公司的比喻来说：Copilot 是给你配了一个助理，帮你减轻工作量；Claude Code 是给你配了一个工程师同事，你告诉他要做什么，他搞定后把结果交给你审查。</p><h3 id="核心差异-tool-use-loop-工具使用循环" tabindex="-1">核心差异：Tool-Use Loop（工具使用循环） <a class="header-anchor" href="#核心差异-tool-use-loop-工具使用循环" aria-label="Permalink to “核心差异：Tool-Use Loop（工具使用循环）”">​</a></h3><p>Claude Code 最本质的差异化能力是 <strong>Tool-Use Loop</strong>。这不是一个营销概念，而是有实质性的架构支撑。</p><p>一个典型的 Claude Code 工作循环是这样的：</p><ol><li><strong>你</strong>说：&quot;在用户表里添加 <code>last_login_at</code> 字段&quot;</li><li><strong>Claude Code</strong> 先读取数据库 schema 文件，理解现有结构</li><li>它编辑 migration 文件，添加新字段定义</li><li>它运行 <code>pnpm migrate</code>，执行数据库变更</li><li>它读取命令输出，确认 migration 成功</li><li>它找到所有引用用户模型的地方，更新相关查询逻辑</li><li>它运行测试套件，验证没有破坏现有功能</li><li>它向你汇报：&quot;已完成。新增字段 <code>last_login_at</code>，更新了 3 处查询，全部 42 个测试通过。&quot;</li></ol><p>这整个过程是<strong>自动连贯</strong>的。Claude Code 在每一步都能看到上一步的执行结果，并根据结果决定下一步行动。这种&quot;看到→行动→观察→调整&quot;的循环，是它区别于所有纯文本生成式 AI 的关键。</p><h3 id="融入而非替换你的工作流" tabindex="-1">融入而非替换你的工作流 <a class="header-anchor" href="#融入而非替换你的工作流" aria-label="Permalink to “融入而非替换你的工作流”">​</a></h3><p>Claude Code 的另一个设计哲学是：<strong>不强制你换工具</strong>。Cursor 和 Windsurf 需要你使用它们定制的 IDE，而 Claude Code 提供了多种接入方式：</p><ul><li><strong>VSCode 扩展</strong>：在你熟悉的 VSCode 侧边栏中运行</li><li><strong>CLI 命令行</strong>：在终端中直接使用 <code>claude</code> 命令</li><li><strong>JetBrains 插件</strong>：支持 IntelliJ IDEA 等 JetBrains IDE</li><li><strong>Web 界面</strong>：通过浏览器使用</li><li><strong>Desktop 应用</strong>：独立的桌面客户端</li></ul><p>对于 VSCode 用户来说尤其自然——你不会感觉到自己&quot;切换了一个工具&quot;。VSCode 还是你的 VSCode，所有的插件、快捷键、主题都保持不变。Claude Code 只是侧边栏中多了一个面板，像一个随时在线的同事。</p><h3 id="几个具体场景-感受差异" tabindex="-1">几个具体场景，感受差异 <a class="header-anchor" href="#几个具体场景-感受差异" aria-label="Permalink to “几个具体场景，感受差异”">​</a></h3><p><strong>场景一：接手一个陌生项目</strong></p><ul><li>Copilot：你逐一打开文件阅读，不明白的地方在 Chat 面板里问，它给你解释。</li><li>Claude Code：你说&quot;介绍这个项目&quot;，它自动遍历项目结构，读取核心文件，梳理架构，生成一份完整的项目概述。</li></ul><p><strong>场景二：修复一个 Bug</strong></p><ul><li>Copilot：你根据错误日志在代码中定位问题，选中相关代码让 Copilot 给出修复建议。</li><li>Claude Code：你粘贴错误日志，说&quot;修复这个 bug&quot;，它自动搜索相关代码，提出修复方案，改代码，跑测试，确认修复。</li></ul><p><strong>场景三：重构一个模块</strong></p><ul><li>Copilot：你手动重构每一处代码，Copilot 在编辑过程中提供补全建议。</li><li>Claude Code：你说&quot;把这个模块从回调风格改成 async/await&quot;，它自动遍历所有调用点，逐一改写，确保逻辑等价。</li></ul><hr><h2 id="_1-5-本书学习路径导航" tabindex="-1">1.5 本书学习路径导航 <a class="header-anchor" href="#_1-5-本书学习路径导航" aria-label="Permalink to “1.5 本书学习路径导航”">​</a></h2><p>本书分为 <strong>8 个模块、40 章</strong>，从零基础到专家级，形成一条完整的成长路径。以下是各篇的概览（完整章节目录请参见<a href="./">首页</a>）：</p><h3 id="模块概览" tabindex="-1">模块概览 <a class="header-anchor" href="#模块概览" aria-label="Permalink to “模块概览”">​</a></h3><table tabindex="0"><thead><tr><th>篇目</th><th>名称</th><th>章节</th><th>一句话描述</th></tr></thead><tbody><tr><td>第一篇</td><td><strong>入门篇</strong></td><td>第 1-4 章</td><td>建立对 AI Agent 编程的完整认知，完成环境搭建</td></tr><tr><td>第二篇</td><td><strong>基础篇</strong></td><td>第 5-9 章</td><td>掌握对话、编辑、终端、Git 四大核心操作</td></tr><tr><td>第三篇</td><td><strong>进阶篇</strong></td><td>第 10-14 章</td><td>理解内部机制，精通上下文管理、权限配置和 CLAUDE.md</td></tr><tr><td>第四篇</td><td><strong>生态篇</strong></td><td>第 15-19 章</td><td>扩展能力边界：MCP、Plugins、Skills、Hooks</td></tr><tr><td>第五篇</td><td><strong>实战篇</strong></td><td>第 20-27 章</td><td>8 个真实开发场景的完整案例演练</td></tr><tr><td>第六篇</td><td><strong>方法论篇</strong></td><td>第 28-31 章</td><td>建立 AI 时代的编程思维和工程方法论</td></tr><tr><td>第七篇</td><td><strong>精通篇</strong></td><td>第 32-36 章</td><td>高级工作流、自定义扩展、团队推广</td></tr><tr><td>第八篇</td><td><strong>贯穿项目</strong></td><td>第 37-40 章</td><td>从零构建 &quot;SmartTodo&quot; 全栈应用，贯穿前七篇技能</td></tr></tbody></table><h3 id="建议阅读路径" tabindex="-1">建议阅读路径 <a class="header-anchor" href="#建议阅读路径" aria-label="Permalink to “建议阅读路径”">​</a></h3><p>不同的读者有不同的起点和需求。以下是根据你的背景推荐的阅读路线：</p><p><strong>零基础/刚接触 AI 编程工具</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>入门篇 → 基础篇 → 进阶篇 → 生态篇 → 实战篇 → 方法论篇 → 精通篇 → 贯穿项目</span></span></code></pre></div><p>从头开始，循序渐进。前四篇建立能力基础，后四篇深化应用。</p><p><strong>有 Copilot/Cursor 使用经验</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第 1 章（建立范式认知）→ 第 3 章（环境搭建）→ 跳至基础篇（第 5 章起）</span></span></code></pre></div><p>你不需要重新认识 AI 编程，但建议快速浏览第 1 章的前两节，理解 Agentic Coding 与 AI 辅助编程的本质区别。然后从环境搭建开始，直接进入核心操作。</p><p><strong>有 Claude Code 使用经验，希望系统提升</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>进阶篇（第 10 章起）→ 生态篇 → 方法论篇 → 精通篇</span></span></code></pre></div><p>你已经会用了，现在是深入理解&quot;为什么&quot;和&quot;还能做什么&quot;的时候。进阶篇揭示内部机制，生态篇打开能力边界。</p><p><strong>团队 Leader / 技术负责人</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>第 1 章（范式认知）→ 第 12 章（CLAUDE.md）→ 第 13 章（配置体系）→ 第 14 章（权限安全）→ 第 34 章（团队推广）</span></span></code></pre></div><p>你的关注点不是个人效率，而是团队落地。重点阅读配置体系、安全保障和推广策略。</p><hr><p>无论你从哪条路径开始，<strong>第 1 章的前两节（1.1 和 1.2）是全书的概念基石</strong>——理解&quot;Agentic Coding 是什么&quot;和&quot;AI Agent 如何工作&quot;，是阅读后续所有内容的前提。如果你时间有限，至少确保这两节你已经理解透彻，再跳到感兴趣的章节。</p><p>准备好了吗？让我们进入第 2 章，开始理解 Claude Code 的两个核心概念：<strong>Agent 与模型</strong>。</p>',103))])}]]);export{i as __pageData,l as default};
